// The app POSTs { rows: [ ...raw export rows...] }. The Webhook node wraps
// the JSON payload under `body`. Fan each row out as its own item so the
// existing Stage 1/2/3 code (which reads $input.all()) runs unchanged.

const first = $input.first().json;
const rows = (first.body && first.body.rows) || first.rows || [];
return rows.map((r) => ({ json: r }));

// === Stage 1 — Validation, normalisation & data-quality flagging ===
// Runs ONCE for all rows so duplicate Company_UUIDs can be detected across the
// whole batch. Emits the app's snake_case schema plus workable / needs_review
// and the exact data_quality_flags the UI renders.

const items = $input.all();

// Pass 1: count UUID occurrences for batch-level duplicate detection.
const uuidCounts = {};
for (const it of items) {
  const u = it.json.Company_UUID;
  if (u) uuidCounts[u] = (uuidCounts[u] || 0) + 1;
}

// DPD → bucket label (must match the app's DPD_BUCKET_ORDER exactly).
function dpdBucket(dpd) {
  if (dpd == null || isNaN(dpd) || dpd <= 0) return null;
  if (dpd <= 30) return "1-30";
  if (dpd <= 60) return "31-60";
  if (dpd <= 90) return "61-90";
  if (dpd <= 180) return "91-180";
  if (dpd <= 365) return "181-365";
  return "365+";
}

const isMissing = (v) => v === null || v === undefined || v === "";

const results = [];
for (const it of items) {
  const r = it.json;
  const flags = [];

  // Coerce numerics (exports deliver strings).
  const amount = isMissing(r.Amount_Due_USD) ? null : Number(r.Amount_Due_USD);
  const dpd = isMissing(r.DPD_days) ? null : Number(r.DPD_days);
  const credit = isMissing(r.Credit_Line_USD) ? null : Number(r.Credit_Line_USD);
  const status = (r.Record_status || "").toString().trim();

  // Amount validity → precise flags.
  const amountValid = amount != null && !isNaN(amount) && amount > 0;
  if (amount == null || isNaN(amount)) flags.push("Missing amount");
  else if (amount <= 0) flags.push("Invalid amount (<=0)");

  // DPD validity → precise flags.
  const dpdValid = dpd != null && !isNaN(dpd) && dpd > 0;
  if (dpd == null || isNaN(dpd)) flags.push("Missing DPD");
  else if (dpd <= 0) flags.push("Invalid DPD (<=0)");

  if (credit == null || isNaN(credit)) flags.push("Missing credit line");
  if (dpdValid && dpd > 365) flags.push("Aged 365+ days");
  if (status === "Pending_review") flags.push("Pending review");
  if (r.Company_UUID && uuidCounts[r.Company_UUID] > 1) flags.push("Duplicate UUID");

  // Workable ONLY if amount + DPD valid AND account is Active.
  const workable = amountValid && dpdValid && status === "Active";

  results.push({
    json: {
      company_uuid: r.Company_UUID,
      segment: r.Segment,
      credit_line_usd: credit,
      collections_channel: r.Collections_Channel,
      amount_due_usd: amount, // coerced value (may be <=0 or null when flagged)
      dpd_days: dpd,
      dpd_bucket: dpdBucket(dpd),
      billing_cycle: r.Billing_Cycle ?? "",
      notes: r.Notes ?? "",
      record_status: status,
      data_source: r.Data_source,
      workable,
      needs_review: !workable,
      data_quality_flags: flags,
    },
  });
}

return results;

// === Stage 2 — Deterministic policy engine ===
// Pure decision table. No LLM, no randomness: identical input → identical policy.
// Rule strings match what the app displays verbatim.
//
// IMPORTANT business rule: the policy is computed whenever the FINANCIALS are
// valid (amount > 0 AND DPD > 0), INDEPENDENT of `workable`. A Pending_review
// account therefore keeps needs_review = true but still carries the policy that
// WOULD apply once review clears. Only records with invalid/missing financials
// get null policy fields. "Full payment" carries upfront_required_usd = 0 (the
// whole balance is due, no partial-upfront arrangement); discounts carry 50%.

const items = $input.all();
const results = [];

for (const it of items) {
  const r = it.json;
  const amount = Number(r.amount_due_usd);
  const dpd = Number(r.dpd_days);
  const financialsValid =
    r.amount_due_usd != null && !isNaN(amount) && amount > 0 &&
    r.dpd_days != null && !isNaN(dpd) && dpd > 0;

  if (!financialsValid) {
    results.push({
      json: {
        ...r,
        recommended_policy: null,
        policy_rule_fired: null,
        upfront_required_usd: null,
      },
    });
    continue;
  }

  const half = Math.round(amount * 0.5 * 100) / 100;
  let policy, rule, upfront;

  if (dpd <= 30) {
    if (amount < 10000) {
      policy = "Full payment, no discount";
      rule = "DPD 1-30 & Amount < $10k";
      upfront = 0;
    } else if (amount <= 50000) {
      policy = "Full payment, no discount";
      rule = "DPD 1-30 & Amount $10k-$50k";
      upfront = 0;
    } else {
      policy = "20% interest discount if 50% paid upfront";
      rule = "DPD 1-30 & Amount > $50k";
      upfront = half;
    }
  } else {
    // financialsValid guarantees dpd > 0, so this branch is strictly DPD > 30.
    policy = "40% interest discount if 50% paid upfront";
    rule = "DPD > 30 (any amount)";
    upfront = half;
  }

  results.push({
    json: {
      ...r,
      recommended_policy: policy,
      policy_rule_fired: rule,
      upfront_required_usd: upfront,
    },
  });
}

return results;

// === Stage 3 — Assemble metadata summary + accounts (the app's CleanedData) ===
// Runs once for all items. Produces exactly { metadata, accounts } so the output
// can be served straight to the Collections Copilot app.

const accounts = $input.all().map((i) => i.json);

const workable = accounts.filter((a) => a.workable).length;
const pending = accounts.filter((a) => a.record_status === "Pending_review").length;

// Duplicate UUIDs = distinct UUIDs that appear more than once.
const counts = {};
for (const a of accounts) counts[a.company_uuid] = (counts[a.company_uuid] || 0) + 1;
const duplicateUuids = Object.values(counts).filter((n) => n > 1).length;

// Exposure = sum of valid amounts due.
const exposure = accounts.reduce((s, a) => {
  const v = Number(a.amount_due_usd);
  return s + (isNaN(v) || v <= 0 ? 0 : v);
}, 0);

const output = {
  metadata: {
    generated_by: "n8n cleaning pipeline",
    pipeline_version: "1.0.0",
    total_records: accounts.length,
    workable_records: workable,
    needs_review_records: accounts.length - workable,
    pending_review_records: pending,
    duplicate_uuids_detected: duplicateUuids,
    total_portfolio_exposure_usd: Math.round(exposure * 100) / 100,
  },
  accounts,
};

// Single item — inspect/copy from the output panel, or pipe to a Google Sheets /
// HTTP Request / DB node to persist for the app to read.
return [{ json: output }];
